#!/usr/bin/env node
// Synthetic happy-path fixtures for each FHIR R4 resource this server exposes.
// Each fixture is generated by the same mapper the route handlers use, then
// POSTed to the public HAPI validator at https://validator.fhir.org/validate.
//
// Usage: node scripts/validate-fhir-fixtures.mjs
// Exits 0 on success, 1 if the validator returns any `error` issue.

import { staffToFhirPractitioner } from "../lib/fhir/practitioner";
import { encounterRowToFhir } from "../lib/fhir/encounter";
