async function validate(resourceType: string, resource: unknown) {
  const res = await fetch(`https://hapi.fhir.org/baseR4/${resourceType}/$validate`, {
    method: "POST",
    headers: { "Content-Type": "application/fhir+json", accept: "application/fhir+json" },
    body: JSON.stringify(resource),
  });
  const outcome = await res.json().catch(() => null);
  if (!res.ok || !outcome) {
    return { resourceType, ok: false, status: res.status, errors: [{ diagnostics: `HTTP ${res.status}` }], warnings: [] };
  }
  type Issue = { severity?: string; diagnostics?: string };
  const issues: Issue[] = Array.isArray(outcome?.issue) ? outcome.issue : [];
  const errors = issues.filter((i) => i.severity === "error" || i.severity === "fatal");
  return {
    resourceType,
    ok: errors.length === 0,
    errors,
    warnings: issues.filter((i: Issue) => i.severity === "warning"),
  };
}

async function main() {
const results = [];
for (const [type, resource] of Object.entries(fixtures)) {
  try {
    const r = await validate(type, resource);
    results.push(r);
    const tag = r.ok ? "PASS" : "FAIL";
    console.log(
      `[${tag}] ${type}  warnings=${r.warnings?.length ?? 0} errors=${r.errors?.length ?? 0}`,
    );
    if (!r.ok) {
      for (const e of r.errors ?? []) {
        console.log("   -", e.diagnostics ?? JSON.stringify(e));
      }
    }
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    console.log(`[ERROR] ${type}`, msg);
    results.push({ resourceType: type, ok: false, errors: [{ diagnostics: msg }], warnings: [] });
  }
}

const failed = results.filter((r) => !r.ok);
if (failed.length) {
  console.log(`\n${failed.length} resource(s) failed HAPI validation.`);
  process.exit(1);
}
console.log("\nAll resources passed HAPI validation.");

}
main().catch((e) => { console.error(e); process.exit(1); });
